var app=app||{};app.htmlUtils={htmlEncodeText:function(t){return $("<div/>").text(t).html()},htmlDecodeText:function(t){return $("<div/>").html(t).text()},htmlEncodeJson:function(t){return JSON.parse(app.htmlUtils.htmlEncodeText(JSON.stringify(t)))},htmlDecodeJson:function(t){return JSON.parse(app.htmlUtils.htmlDecodeText(JSON.stringify(t)))}};